# Deterministic result aggregation for parallel subagent outputs
from typing import List, Dict, Any

def aggregate_security_reviews(subagent_results: List[Dict]) -> Dict:
    severity_rank = {"critical": 4, "high": 3, "medium": 2, "low": 1, "none": 0}

    # Group findings by (category, first_line) as a stable key
    grouped: Dict[tuple, Dict] = {}
    for result in subagent_results:
        for finding in result.get("findings", []):
            key = (finding["category"],
                   finding["line_numbers"][0] if finding["line_numbers"] else -1)
            existing = grouped.get(key)
            if existing is None or (severity_rank[finding["severity"]] >
                                     severity_rank[existing["severity"]]):
                grouped[key] = finding  # Keep highest severity report of this issue

    overall_risks = [r.get("overall_risk", "none") for r in subagent_results]
    overall_risk = max(overall_risks, key=lambda s: severity_rank.get(s, 0))

    return {
        "findings": list(grouped.values()),
        "overall_risk": overall_risk,
        "subagent_count": len(subagent_results),
        "findings_before_dedup": sum(len(r.get("findings", [])) for r in subagent_results),
    }

async def multi_review_pipeline(code: str, client) -> Dict:
    import asyncio
    tasks = [run_security_review(code, client) for _ in range(3)]
    results = await asyncio.gather(*tasks, return_exceptions=True)
    valid_results = [r for r in results if not isinstance(r, Exception)]
    if not valid_results:
        raise RuntimeError("All subagents failed")
    return aggregate_security_reviews(valid_results)
